command:example.dev:code:
$GetInfisicalProjectResult = Get-InfisicalProject | Where-Object { $_.Slug -eq 'platform-telemetry' }
$UpdateInfisicalProjectParameters = New-Object -TypeName 'System.Collections.Specialized.OrderedDictionary' -ArgumentList ([System.StringComparer]::OrdinalIgnoreCase) $UpdateInfisicalProjectParameters.ProjectId = $GetInfisicalProjectResult.Id $UpdateInfisicalProjectParameters.Name = 'Platform Telemetry (v2)' $UpdateInfisicalProjectParameters.Description = 'Migrated to v2 pipeline' $UpdateInfisicalProjectParameters.AutoCapitalization = $False $UpdateInfisicalProjectParameters.Verbose = $True
$UpdateInfisicalProjectResult = Update-InfisicalProject @UpdateInfisicalProjectParameters

$GetInfisicalCertificateAuthorityListResult = Get-InfisicalCertificateAuthority | Where-Object { $_.FriendlyName -eq 'Issuing CA - Platform' }
$GetInfisicalCertificateAuthorityParameters = New-Object -TypeName 'System.Collections.Specialized.OrderedDictionary' -ArgumentList ([System.StringComparer]::OrdinalIgnoreCase) $GetInfisicalCertificateAuthorityParameters.CaId = $GetInfisicalCertificateAuthorityListResult.Id $GetInfisicalCertificateAuthorityParameters.ProjectId = $ConnectInfisicalParameters.ProjectId $GetInfisicalCertificateAuthorityParameters.Verbose = $True
$GetInfisicalCertificateAuthorityResult = Get-InfisicalCertificateAuthority @GetInfisicalCertificateAuthorityParameters

$GetInfisicalCertificateAuthorityListResult = Get-InfisicalCertificateAuthority | Where-Object { $_.FriendlyName -eq 'Issuing CA - Platform' }
$GetInfisicalCertificateParameters = New-Object -TypeName 'System.Collections.Specialized.OrderedDictionary' -ArgumentList ([System.StringComparer]::OrdinalIgnoreCase) $GetInfisicalCertificateParameters.ProjectId = $ConnectInfisicalParameters.ProjectId $GetInfisicalCertificateParameters.CommonName = $env:COMPUTERNAME $GetInfisicalCertificateParameters.FriendlyName = 'web-tier' $GetInfisicalCertificateParameters.Status = 'active' $GetInfisicalCertificateParameters.CaId = @($GetInfisicalCertificateAuthorityListResult.Id) $GetInfisicalCertificateParameters.Limit = 100 $GetInfisicalCertificateParameters.Verbose = $True
$GetInfisicalCertificateListResult = Get-InfisicalCertificate @GetInfisicalCertificateParameters

$GetInfisicalCertificateAuthorityListResult = Get-InfisicalCertificateAuthority | Where-Object { $_.FriendlyName -eq 'Issuing CA - Platform' }
$SearchInfisicalCertificateParameters = New-Object -TypeName 'System.Collections.Specialized.OrderedDictionary' -ArgumentList ([System.StringComparer]::OrdinalIgnoreCase) $SearchInfisicalCertificateParameters.ProjectId = $ConnectInfisicalParameters.ProjectId $SearchInfisicalCertificateParameters.CommonName = $env:COMPUTERNAME $SearchInfisicalCertificateParameters.Status = 'active' $SearchInfisicalCertificateParameters.CaId = @($GetInfisicalCertificateAuthorityListResult.Id) $SearchInfisicalCertificateParameters.KeyAlgorithm = @('RSA') $SearchInfisicalCertificateParameters.NotAfterTo = (Get-Date).AddDays(30) $SearchInfisicalCertificateParameters.SortBy = 'notAfter' $SearchInfisicalCertificateParameters.SortOrder = 'asc' $SearchInfisicalCertificateParameters.Limit = 100 $SearchInfisicalCertificateParameters.Verbose = $True
$SearchInfisicalCertificateResult = Search-InfisicalCertificate @SearchInfisicalCertificateParameters
